#include <random>
#include <iostream>

std::mt19937 rng{ 42u };

int main()
{
    int n;
    std::cin >> n;

    std::uniform_int_distribution<int> coin{ 0, 1 };

    for (int i = 0; i < n; ++i)
    {
        int flip = coin(rng);
        if (flip == 0)
            std::cout << "Heads\n";
        else
            std::cout << "Tails\n";
    }

    return 0;
}

